const input = $('Called by Agent').first().json;
try {
  const raw = $input.first().json.content[0].text;
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const content = JSON.parse(cleaned);
  return [{ json: {
    status: 'completed',
    workflow: '09_seo_content_writer',
    project: input.project || input.parameters?.project || 'profit',
    topic: input.topic || input.parameters?.topic || input.chatInput || 'private swimming lessons for kids',
    target_audience: input.target_audience || input.parameters?.target_audience || 'parents of children aged 4-12',
    title: content.title,
    meta_description: content.meta_description,
    target_keywords: content.target_keywords,
    article: content.article,
    internal_links: content.internal_links,
    word_count: content.word_count,
    reading_time_minutes: content.reading_time_minutes,
    seo_score_notes: content.seo_score_notes,
    completedAt: new Date().toISOString()
  } }];
} catch (e) {
  const raw = $input.first().json.content?.[0]?.text || 'No content';
  return [{ json: {
    status: 'completed',
    workflow: '09_seo_content_writer',
    content_raw: raw,
    parse_note: 'Response was not valid JSON, returning raw text',
    completedAt: new Date().toISOString()
  } }];
}
